const question = $('Normalize Input').first().json.question ?? '';
const size = Number($('Normalize Input').first().json.size || 2);
const sessionId = $('Normalize Input').first().json.sessionId ?? '';
const text = question.toLowerCase();

const deliveryKeywords = ['배송', '택배', '운송장', '출고', '도착', '늦', '지연', 'shipment', 'delivery', 'tracking'];
const refundKeywords = ['환불', '교환', '반품', '오배송', '클레임', '취소', 'refund', 'exchange', 'return'];
const explicitRefundKeywords = [...refundKeywords, '환불받', '돈 돌려', '돌려받', '반송', '반품비'];

const hasDelivery = deliveryKeywords.some((keyword) => text.includes(keyword));
const hasRefund = refundKeywords.some((keyword) => text.includes(keyword));
const hasExplicitRefund = explicitRefundKeywords.some((keyword) => text.includes(keyword));

if (hasDelivery || hasRefund) {
  const agents = [];
  if (hasDelivery) agents.push('delivery');
  if (hasRefund) agents.push('refundExchange');
  return [
    {
      json: {
        question,
        size,
        sessionId,
        routing: {
          agents,
          strategy: 'rule_based_keywords',
          reason: `keyword routing: delivery=${hasDelivery}, refundExchange=${hasRefund}`,
          raw: JSON.stringify({ agents, hasDelivery, hasRefund })
        }
      }
    }
  ];
}

const routerPrompt = `Route this Korean support question. Return JSON only: {"agents":["delivery"],"reason":"short"}. Agents: delivery=shipping/arrival/tracking/not received/order not arrived; refundExchange=refund/exchange/return/cancel/wrong item/claim. Strict rules: choose refundExchange only when refund, exchange, return, cancel, wrong item, or claim is explicit. Missing/not arrived/where is my order => delivery only. Choose both only when both shipping and refund/exchange intent are explicit. Question: ${question}`;

let parsed;
let raw = '';
try {
  const body = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:11434/api/chat',
    headers: { 'Content-Type': 'application/json' },
    body: {
      model: 'llama3.1:8b',
      stream: false,
      format: 'json',
      options: {
        num_predict: 32,
        temperature: 0,
        num_ctx: 512
      },
      messages: [
        {
          role: 'user',
          content: routerPrompt
        }
      ]
    },
    json: true
  });
  raw = body.message?.content ?? '';
  parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch (error) {
  parsed = {
    agents: ['delivery'],
    reason: 'LLM router failed, defaulting to delivery.'
  };
  raw = String(error.message ?? error);
}

let agents = Array.isArray(parsed.agents) ? parsed.agents : [];
agents = agents.filter((agent) => ['delivery', 'refundExchange'].includes(agent));
if (!hasExplicitRefund) {
  agents = agents.filter((agent) => agent !== 'refundExchange');
}
if (agents.length === 0) agents = ['delivery'];

return [
  {
    json: {
      question,
      size,
      sessionId,
      routing: {
        agents,
        strategy: 'llm_router_fallback',
        reason: parsed.reason ?? 'Ambiguous question routed by LLM.',
        raw
      }
    }
  }
];

const routed = $('Hybrid Router').first().json;
const sessionId = routed.sessionId ?? '';
let agents = Array.isArray(routed.routing?.agents) ? routed.routing.agents : [];
agents = agents.filter((agent) => ['delivery', 'refundExchange'].includes(agent));
if (agents.length === 0) agents = ['delivery'];

return [
  {
    json: {
      question: routed.question,
      size: Number(routed.size || 2),
      sessionId,
      routing: {
        agents,
        strategy: routed.routing?.strategy ?? 'hybrid_router',
        reason: routed.routing?.reason ?? 'hybrid routing fallback',
        raw: routed.routing?.raw ?? ''
      }
    }
  }
];

const routing = $('Parse Routing').first().json.routing;
const response = $('Spring Multi-Agent API').first().json;

return [
  {
    json: {
      question: response.question,
      routing,
      finalAnswer: response.finalAnswer,
      agentResults: response.agentResults ?? [],
      metadata: {
        ...(response.metadata ?? {}),
        springApi: 'http://backend:8080/agents/multi-answer',
        routerStrategy: routing.strategy ?? 'hybrid_router'
      }
    }
  }
];
